/**
 * @summary Update schedule settings
 */
export const getUpdateScheduleUrl = () => {
  return `/api/settings/schedule`;
};

export const updateSchedule = async (
  scheduleSettings: ScheduleSettings,
  options?: RequestInit,
): Promise<ScheduleSettings> => {
  return customFetch<ScheduleSettings>(getUpdateScheduleUrl(), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(scheduleSettings),
  });
};

export const getUpdateScheduleMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateSchedule>>,
    TError,
    { data: BodyType<ScheduleSettings> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateSchedule>>,
  TError,
  { data: BodyType<ScheduleSettings> },
  TContext
> => {
  const mutationKey = ["updateSchedule"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateSchedule>>,
    { data: BodyType<ScheduleSettings> }
  > = (props) => {
    const { data } = props ?? {};

    return updateSchedule(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateScheduleMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateSchedule>>
>;
export type UpdateScheduleMutationBody = BodyType<ScheduleSettings>;
export type UpdateScheduleMutationError = ErrorType<unknown>;

